import{c as a,Q as t,j as s,m as n}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"Releases & Deployments","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/releases.md","filePath":"guide/concepts/releases.md","lastUpdated":1778862269000}'),o={name:"guide/concepts/releases.md"};function r(i,e,l,d,p,c){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="releases-deployments" tabindex="-1">Releases &amp; Deployments <a class="header-anchor" href="#releases-deployments" aria-label="Permalink to &quot;Releases &amp; Deployments&quot;">​</a></h1><p>A <strong>release</strong> is a versioned bundle of code and configuration that the Console ships to instances. Releases are the only mechanism the Console uses to change what is running on instances — there are no out-of-band updates.</p><h2 id="release-types" tabindex="-1">Release types <a class="header-anchor" href="#release-types" aria-label="Permalink to &quot;Release types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>What it is</th><th>Versioning</th></tr></thead><tbody><tr><td><strong>Feature</strong></td><td>A planned change that updates one or more services to new Docker images.</td><td>Semantic version. You pick patch / minor / major when creating.</td></tr><tr><td><strong>Hotfix</strong></td><td>A critical fix that bypasses the normal queue. Hotfixes auto-deploy and pause pending feature releases on the same line.</td><td>Always a patch bump, regardless of input.</td></tr><tr><td><strong>Config</strong></td><td>Environment-variable changes only. No service image changes.</td><td>Auto-incrementing counter (Config #1, #2, …).</td></tr></tbody></table><p>A Config release will be rejected if the preview shows no environment delta against the last deployed state — there is nothing to ship.</p><h2 id="anatomy-of-a-release" tabindex="-1">Anatomy of a release <a class="header-anchor" href="#anatomy-of-a-release" aria-label="Permalink to &quot;Anatomy of a release&quot;">​</a></h2><p>A release contains:</p><ul><li>A <strong>set of services</strong> with target Docker images (for Feature and Hotfix).</li><li>The <strong>environment variables</strong> in effect, captured as a snapshot. Changes since the last release are computed as create / update / delete deltas.</li><li>A <strong>release notes</strong> rich-text document (required for Feature and Hotfix, optional for Config). These are what customers see in the Changelog.</li><li>The <strong>initiator</strong>, <strong>created</strong> time, <strong>deployed</strong> time, and <strong>completed</strong> time.</li></ul><h2 id="the-pipeline" tabindex="-1">The pipeline <a class="header-anchor" href="#the-pipeline" aria-label="Permalink to &quot;The pipeline&quot;">​</a></h2><p>The pipeline is configured globally on the <a href="./../admin/release-configuration">Release Configuration</a> page. It defines:</p><ul><li><strong>Stages</strong> — an ordered sequence (Stage 01, Stage 02, …). Each stage groups one or more environments.</li><li><strong>Parallel environments</strong> — environments in the same stage deploy together.</li><li><strong>Managed services</strong> — the services the pipeline operates on. Services not listed are ignored.</li><li><strong>Approval mode</strong> — Disabled, All Instance SPOCs, or Any Instance SPOC.</li><li><strong>DevOps trigger</strong> — optional extra gate that requires an explicit trigger after approval.</li><li><strong>SLA thresholds</strong> — reminder, escalation, and stalled times (days for normal releases, hours for hotfixes).</li><li><strong>Escalation contacts</strong> — who gets paged if a release sits too long.</li></ul><h2 id="release-lifecycle" tabindex="-1">Release lifecycle <a class="header-anchor" href="#release-lifecycle" aria-label="Permalink to &quot;Release lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>draft ──▶ in_progress ──▶ completed</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  ├──▶ paused ──▶ in_progress</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  ├──▶ failed ─┐</span></span>
<span class="line"><span>                  │            ├──▶ archived</span></span>
<span class="line"><span>                  ├──▶ rolled_back ─┤</span></span>
<span class="line"><span>                  │            │</span></span>
<span class="line"><span>                  └──▶ cancelled ──┘</span></span></code></pre></div><ul><li><strong>Draft.</strong> Created but not yet deployed. The author can review and click <strong>Deploy</strong> when ready.</li><li><strong>In Progress.</strong> Flowing through stages. Stages may show as <code>pending</code>, <code>deploying</code>, <code>awaiting_approval</code>, <code>awaiting_trigger</code>, <code>deployed</code>, <code>failed</code>, <code>skipped</code>, or <code>rolled_back</code>.</li><li><strong>Paused.</strong> Awaiting human action — either an approval, a trigger, or a manual hold.</li><li><strong>Completed.</strong> All stages succeeded.</li><li><strong>Failed / Rolled Back / Cancelled.</strong> Terminal states. The release can be <strong>archived</strong> to keep the list clean.</li><li><strong>Archived.</strong> Hidden from the default Releases view. Within 30 days of archival the release can be <strong>unarchived</strong>; after that, per-service configuration, environment-version pins, and logs are permanently purged.</li></ul><h2 id="stages-approvals-and-triggers" tabindex="-1">Stages, approvals, and triggers <a class="header-anchor" href="#stages-approvals-and-triggers" aria-label="Permalink to &quot;Stages, approvals, and triggers&quot;">​</a></h2><p>For each stage, the Console shows which environments and instances are involved, and surfaces the action you need to take:</p><ul><li><strong>Approve</strong> — if the stage is in <code>awaiting_approval</code> and you are a SPOC for any of the affected instances.</li><li><strong>Trigger</strong> — if the stage is in <code>awaiting_trigger</code> (DevOps gate enabled) and you have permission.</li><li><strong>Retry</strong> / <strong>Skip</strong> / <strong>Rollback</strong> — per-instance actions in the Instance Deployments section.</li></ul><p>Approvals are recorded with the SPOC&#39;s identity and a timestamp. Triggers and rollbacks are recorded the same way. The full activity log on the release detail page is the source of truth.</p><h2 id="what-customers-see" tabindex="-1">What customers see <a class="header-anchor" href="#what-customers-see" aria-label="Permalink to &quot;What customers see&quot;">​</a></h2><p>Customers do not see the pipeline. They see the <strong>Changelog</strong> — a curated list of completed releases with their release notes, grouped by month. Config releases without notes are excluded. Customers reach the changelog from the Customer Portal sidebar (&quot;What&#39;s New&quot;).</p>`,20)])])}const u=a(o,[["render",r]]);export{h as __pageData,u as default};
